       position: absolute;\n            right: 0;\n            top: 50%;\n            transform: translateY(-50%);\n            width: 55%;\n            height: auto;\n            opacity: 0.12;\n        }\n.erp-hero-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 60px;\n            align-items: center;\n            position: relative;\n            z-index: 1;\n        }\n.erp-hero-content {\n            max-width: 600px;\n        }\n.erp-hero-badge {\n            display: inline-flex;\n            align-items: center;\n            gap: 10px;\n            background: rgba(0, 175, 240, 0.1);\n            border: 1px solid rgba(0, 175, 240, 0.3);\n            padding: 10px 20px;\n            border-radius: 50px;\n            color: #0369a1;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            margin-bottom: 24px;\n        \n            line-height: 17.6px;\n\n            -webkit-font-smoothing: auto;\n}\n.erp-hero-badge::before {\n            content: \'\';\n            width: 8px;\n            height: 8px;\n            background: #0369a1;\n            border-radius: 50%;\n        }\n.erp-hero h1 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(36px, 4.5vw, 52px);\n            font-weight: 700;\n            color: #ffffff;\n            margin: 0 0 24px 0;\n            line-height: 1.15;\n            letter-spacing: -0.02em;\n        }\n.erp-hero h1 .highlight {\n            color: #0369a1;\n        \n            -webkit-font-smoothing: auto;\n}\n.erp-hero-subtitle {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 19px;\n            color: rgba(255, 255, 255, 0.8);\n            line-height: 1.7;\n            margin-bottom: 36px;\n        \n            -webkit-font-smoothing: auto;\n}\n.erp-hero-ctas {\n            display: flex;\n            gap: 16px;\n            flex-wrap: wrap;\n            margin-bottom: 48px;\n        }\n.erp-hero-stats {\n            display: flex;\n            gap: 40px;\n            padding-top: 32px;\n            border-top: 1px solid rgba(255, 255, 255, 0.1);\n        }\n.erp-hero-stat {\n            text-align: left;\n        }\n.erp-hero-stat-number {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 32px;\n            font-weight: 800;\n            color: #0369a1;\n            letter-spacing: -0.02em;\n        \n            line-height: 51.2px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.erp-hero-stat-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            color: rgba(255, 255, 255, 0.75);\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            margin-top: 4px;\n        \n            line-height: 16px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.erp-hero-visual {\n            position: relative;\n        }\n.erp-dashboard-mockup {\n            background: #000864;\n            border-radius: 16px;\n            border: 1px solid rgba(255, 255, 255, 0.1);\n            padding: 20px;\n            box-shadow: 0 40px 80px rgba(0, 0, 0, 0.4);\n        }\n.mockup-content {\n            background: rgba(255, 255, 255, 0.03);\n            border-radius: 8px;\n            padding: 20px;\n            min-height: 280px;\n        }\n.mockup-grid {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 12px;\n            margin-bottom: 16px;\n        }\n.mockup-card {\n            background: rgba(255, 255, 255, 0.05);\n            border-radius: 8px;\n            padding: 16px;\n        }\n.mockup-card-value {\n            font-family: \'Noto Sans\',