    padding: 100px 0;\n            background: #ffffff;\n            -webkit-font-smoothing: auto;\n        }\n.pain-section p { padding-bottom: 0 !important; }\n.pain-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n        }\n.pain-header {\n            text-align: center;\n            margin-bottom: 64px;\n        }\n.pain-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            color: #DC2626;\n            text-transform: uppercase;\n            letter-spacing: 0.15em;\n            margin-bottom: 16px;\n        \n            line-height: 17.6px;\n\n            -webkit-font-smoothing: auto;\n}\n.pain-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 40px;\n            font-weight: 700;\n            color: #000864;\n            margin: 0 0 16px 0;\n            letter-spacing: -0.02em;\n            line-height: 64px;\n            -webkit-font-smoothing: auto;\n        }\n.pain-subtitle {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            color: #5b6b80;\n            max-width: 600px;\n            margin: 0 auto;\n        \n            line-height: 28.8px;\n\n            -webkit-font-smoothing: auto;\n}\n.pain-grid {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 28px;\n        }\n.pain-card {\n            background: #ffffff;\n            border-radius: 20px;\n            padding: 36px;\n            border: 1px solid #e8eef3;\n            box-shadow: 0 4px 24px rgba(0, 0, 0, 0.04);\n            transition: all 0.4s ease;\n            position: relative;\n        }\n.pain-card:hover {\n            border-color: #0369a1;\n            box-shadow: 0 12px 48px rgba(3, 105, 161, 0.12);\n        }\n.pain-card:hover .pain-card-icon {\n            background: linear-gradient(135deg, #0369a1, #003CC8);\n        }\n.pain-card:hover .pain-card-icon svg {\n            stroke: #ffffff;\n        }\n.pain-card-icon {\n            width: 56px;\n            height: 56px;\n            background: linear-gradient(135deg, #fee2e2, #fecaca);\n            border-radius: 14px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin-bottom: 20px;\n            transition: all 0.4s ease;\n        }\n.pain-card-icon svg {\n            width: 28px;\n            height: 28px;\n            stroke: #DC2626;\n            stroke-width: 1.5;\n            fill: none;\n            transition: all 0.4s ease;\n        }\n.pain-card-problem {\n            margin-bottom: 24px;\n            padding-bottom: 24px;\n            border-bottom: 1px dashed #e8eef3;\n        }\n.pain-card-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            font-weight: 500;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            margin-bottom: 10px;\n        \n            line-height: 16px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.pain-card-label.problem { color: #DC2626; }\n.pain-card-label.solution { color: rgb(4, 120, 87); }\n.pain-card-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            font-weight: 600;\n            color: #000864;\n            margin-bottom: 10px;\n            line-height: 1.4;\n        \n            -webkit-font-smoothing: auto !important;\n}\n.pain-card-desc {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 15px;\n            color: #5b6b80;\n            line-height: 1.65;\n        \n            -webkit-font-smoothing: auto !important;\n}\n.pain-card-solution-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 16px;\n            font-weight: 600;\n            color: #000864;\n            margin-bottom: 8px;\n            line-height: 25.6px;\n            -webkit-font-smoothing: auto !important;\n}\n@media (max-width: 1024px) {\n            .erp-hero-inner {\n                grid-template-columns: 1fr;\n                text-align: center;\n            }\n\n            .erp-hero-content {\n                max-width: 100%;\n            }\n\n            .erp-hero-stats {\n                justify-content: center;\n            }\n\n            .erp-hero-visual {\n                display: none;\n            }\n\n            .erp-hero-bg svg {\n                opacity: 0.06;\n                width: 80%;\n                right: -20%;\n            }\n\n            .pain-grid, .products-comparison {\n                grid-template-columns: 1fr;\n                max-width: 600px;\n                margin-left: auto;\n                margin-right: auto;\n            }\n\n            .integration-visual {\n                flex-direction: column;\n            }\n\n            .integration-node {\n                width: auto;\n                height: auto;\n            }\n\n            .integration-arrow {\n                transform: rotate(90deg);\n            }\n\n            .boi-callout-grid {\n                grid-template-columns: 1fr !important;\n                text-align: center;\n            }\n\n            .boi-callout-grid > div:first-child {\n                text-align: center;\n            }\n\n            .erpii-modules-grid {\n                grid-template-columns: repeat(2, 1fr);\n            }\n\n            .erp-trust-callout {\n                flex-direction: column;\n            }\n        }\n@media (prefers-reduced-motion: reduce) {\n            .erp-hero-content,\n            .erp-hero::before,\n            .erp-hero-badge::before,\n            .erp-dashboard-mockup,\n            .pain-card,\n            .pain-card-icon,\n            .product-card,\n            .weapon-card,\n            .challenge-icon,\n            .integration-link,\n            .erp-use-case-pill,\n            .erp-erpii-accordion summary,\n            .boi-enforcement-cta,\n            .dw-d-parallax,\n            .dw-wave-flow,\n            .dw-wave-fade,\n            .dw-d-bg {\n                animation: none !important;\n                transition: none !important;\n            }\n        }\n\n/* TODO: HOVER STATES using global classes (port manually) */\n/* .solution-card:hover{border-color:#0369a1;box-shadow:0 12px 40px rgba(3, 105, 161, 0.12)} */\n/* .solution-card:hover .solution-icon{background:linear-gradient(135deg, #0369a1, #003CC8)} */\n/* .solution-card:hover .solution-icon svg{stroke:#fff} */\n.solution-icon{width:64px;height:64px;background:linear-gradient(135deg, rgba(3, 105, 161, 0.15), rgba(3, 105, 161, 0.05));border-radius:16px;display:flex;align-items:center;justify-content:center;margin-bottom:24px;transition:all 0.4s ease}\n.solution-icon svg{width:28px;height:28px;stroke:#0369a1;stroke-width:1.5;fill:none}\n/* .solution-card h3{font-family:\'Noto Sans\', sans-serif;font-size:22px;color:#000864;margin-bottom:12px} */\n/* .solution-card > p{font-size:15px;color:#5b6b80;line-height:1.7;margin-bottom:20px} */\n/* .solution-features{display:flex;flex-direction:column;gap:10px} */\n/* .solution-feature{display:flex;align-items:center;gap:10px;font-size:14px;color:#475569} */\n.solution-feature svg{width:18px;height:18px;color:#0369a1;flex-shrink:0}\n/* @media (max-width:640px){.auto-hero, .elec-hero, .metal-hero{padding:120px 0 80px}.auto-hero h1, .elec-hero h1, .metal-hero h1{font-size:32px}.auto-hero-subtitle, .elec-hero-subtitle, .metal-hero-subtitle{font-size:17px}.auto-hero-stats, .elec-hero-stats, .metal-hero-stats{flex-direction:column;gap:24px}.auto-hero-stat-value, .elec-hero-stat-value, .metal-hero-stat-value{font-size:36px}.stake-card, .challenge-card{padding:32px 24px}.solution-card{padding:32px}.cta-section h2{font-size:28px}.cta-buttons{flex-direction:column}} */\n\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration */\n.dw-d-bg{position:absolute;top:50%;right:-10%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;transform:translateY(-50%);opacity:0.12;pointer-events:none;z-index:0}\n/* === PRODUCTS (S4) === */\n/* TODO: Review and remap class selectors to use pro prefix */\n/* TODO: Add section container: .products-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.products-section {\n            padding: 100px 0;\n            background: #F5F7FA;\n            position: relative;\n            -webkit-font-smoothing: auto;\n            -moz-osx-font-smoothing: auto;\n        }\n.products-section p{padding-bottom:0}\n.products-section h4{line-height:1.6}\n.products-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n        }\n.products-header {\n            text-align: center;\n            margin-bottom: 64px;\n        }\n.products-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            color: #0369a1;\n            text-transform: uppercase;\n            letter-spacing: 0.15em;\n            margin-bottom: 16px;\n            line-height: 1.6;\n        }\n.products-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 36px;\n            font-weight: 700;\n            color: #000864;\n            margin: 0 0 16px 0;\n            line-height: 57.6px;\n        }\n.products-subtitle {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            color: #5b6b80;\n            max-width: 550px;\n            margin: 0 auto;\n            line-height: 1.6;\n        }\n.products-comparison {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 32px;\n        }\n/* Product cards — from theme */\n/* Product card — container */\n.product-card{background:#ffffff;border-radius:24px;overflow:hidden;border:2px solid #e8eef3;padding:32px;transition:all 0.4s cubic-bezier(0.4, 0, 0.2, 1)}\n.product-card:hover{border-color:#0369a1;box-shadow:0 20px 60px rgba(3,105,161,0.15)}\n/* Product card — header with gradient */\n.product-card-header{padding:36px 36px 28px;background:linear-gradient(135deg, #0f1419 0%, #1a2632 100%);position:relative}\n.product-card-header::after{content:\'\';position:absolute;bottom:0;left:0;right:0;height:4px;background:linear-gradient(90deg, #0369a1, #7ec8f2)}\n/* Product card — badge */\n.product-card-badge{display:inline-block;background:rgba(0,175,240,0.2);border:1px solid rgba(0,175,240,0.3);color:#7ec8f2;font-family:\'JetBrains Mono\', monospace;font-size:10px;font-weight:500;padding:6px 14px;border-radius:9999px;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:16px;line-height:1.6}\n/* Product card — name */\n.product-card-name{font-family:\'Noto Sans\', sans-serif;font-size:20px;font-weight:600;color:#000864;margin-bottom:12px;line-height:1.6}\n/* Product card — tagline + desc */\n.product-card-tagline,.product-card-desc{font-family:\'Noto Sans\', sans-serif;font-size:14px;color:#5b6b80;line-height:1.6;margin-bottom:16px}\n/* Product card — body */\n.product-card-body{padding:0}\n.product-features{list-style:none;padding:0;margin:0 0 28px 0}\n.product-features li{font-family:\'Noto Sans\', sans-serif;font-size:15px;color:#000864;padding:12px 0;border-bottom:1px solid #f0f4f8;display:flex;align-items:center;gap:14px;line-height:1.6}\n.product-features li:last-child{border-bottom:none}\n.product-features .check-icon{width:22px;height:22px;background:linear-gradient(135deg, #0369a1, #003CC8);border-radius:6px;display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.product-features .check-icon svg{width:12px;height:12px;stroke:#ffffff;stroke-width:3;fill:none}\n.product-best-for{background:#F5F7FA;border-radius:12px;padding:20px 24px;margin-bottom:24px}\n.product-best-for-label{font-family:\'JetBrains Mono\', monospace;font-size:11px;font-weight:500;color:#0369a1;text-transform:uppercase;letter-spacing:0.15em;margin-bottom:8px}\n.product-best-for-text{font-family:\'Noto Sans\', sans-serif;font-size:14px;color:#666666;line-height:1.5}\n.erp-use-case-pills {\n            display: flex;\n            gap: 12px;\n            justify-content: center;\n            flex-wrap: wrap;\n            margin-bottom: 48px;\n        }\n.erp-use-case-pill {\n            display: inline-block;\n            padding: 10px 22px;\n            background: #ffffff;\n            border: 1px solid #e8eef3;\n            border-radius: 8px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 13px;\n            font-weight: 500;\n            color: #000864;\n            text-decoration: none;\n            transition: all 0.3s ease;\n            line-height: 1.6;\n        }\n.erp-use-case-pill:hover,\n        .erp-use-case-pill:focus {\n            background: #0369a1;\n            color: #ffffff;\n            border-color: #0369a1;\n        }\n.erp-erpii-accordion {\n            margin-top: 24px;\n            border: 1px solid #e8eef3;\n            border-radius: 12px;\n            overflow: hidden;\n        }\n.erp-erpii-accordion summary {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 15px;\n            font-weight: 600;\n            color: #0369a1;\n            padding: 16px 24px;\n            cursor: pointer;\n            list-style: none;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            background: #F5F7FA;\n            transition: background 0.2s ease;\n        }\n.erp-erpii-accordion summary::-webkit-details-marker { display: none; }\n.erp-erpii-accordion summary .accordion-icon {\n            font-size: 18px;\n            color: #0369a1;\n            transition: transform 0.2s ease;\n            flex-shrink: 0;\n            margin-left: 12px;\n        }\n.erp-erpii-accordion[open] summary .accordion-icon {\n            transform: rotate(45deg);\n        }\n.erp-erpii-accordion .erpii-content {\n            padding: 24px;\n            background: #ffffff;\n        }\n.erp-erpii-accordion .erpii-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 20px;\n            font-weight: 700;\n            color: #000864;\n            margin: 0 0 8px 0;\n            line-height: 1.6;\n        }\n.erp-erpii-accordion .erpii-subtitle {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 14px;\n            color: #5b6b80;\n            line-height: 1.6;\n            margin: 0 0 20px 0;\n        }\n.erpii-modules-grid {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 16px;\n        }\n.erpii-module-card {\n            background: #F5F7FA;\n            border-radius: 12px;\n            padding: 16px;\n            text-align: center;\n        }\n.erpii-module-icon {\n            width: 40px;\n            height: 40px;\n            background: linear-gradient(135deg, rgba(3, 105, 161, 0.12), rgba(3, 105, 161, 0.04));\n            border-radius: 10px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin: 0 auto 10px;\n        \n            background-image: linear-gradient(135deg, rgba(0, 175, 240, 0.12), rgba(0, 175, 240, 0.04));\n}\n.erpii-module-icon svg {\n            width: 20px;\n            height: 20px;\n            stroke: #0369a1;\n            stroke-width: 1.5;\n            fill: none;\n        }\n.erpii-module-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            font-weight: 500;\n            color: #0369a1;\n            text-transform: uppercase;\n            letter-spacing: 0.08em;\n            margin-bottom: 4px;\n            line-height: 1.6;\n        }\n.erpii-module-name {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 13px;\n            font-weight: 600;\n            color: #000864;\n            margin-bottom: 4px;\n            line-height: 1.6;\n        }\n.erpii-module-desc {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 12px;\n            color: #5b6b80;\n            line-height: 1.4;\n        }\n.erp-proven-in {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 13px;\n            font-style: italic;\n            color: #5b6b80;\n            margin-top: 16px;\n            margin-bottom: 16px;\n            padding-top: 16px;\n            border-top: 1px solid #f0f4f8;\n            line-height: 22.4px;\n        }\n.erp-trust-callout {\n            margin-top: 24px;\n            background: #f0f9ff;\n            border: 1px solid #0369a1;\n            border-radius: 12px;\n            padding: 24px;\n            display: flex;\n            gap: 16px;\n            align-items: flex-start;\n        }\n.erp-trust-icon {\n            width: 44px;\n            height: 44px;\n            background: linear-gradient(135deg, rgba(3, 105, 161, 0.15), rgba(3, 105, 161, 0.05));\n            border-radius: 10px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            flex-shrink: 0;\n        \n            background-image: linear-gradient(135deg, rgba(0, 175, 240, 0.15), rgba(0, 175, 240, 0.05));\n}\n.erp-trust-icon svg {\n            width: 22px;\n            height: 22px;\n            stroke: #0369a1;\n            stroke-width: 1.5;\n            fill: none;\n        }\n.erp-trust-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 16px;\n            font-weight: 700;\n            color: #000864;\n            margin: 0 0 6px 0;\n            line-height: 1.6;\n        }\n.erp-trust-body {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 14px;\n            color: #5b6b80;\n            line-height: 1.6;\n            margin: 0 0 16px 0;\n        }\n@media (max-width: 1024px) {\n            .erp-hero-inner {\n                grid-template-columns: 1fr;\n                text-align: center;\n            }\n\n            .erp-hero-content {\n                max-width: 100%;\n            }\n\n            .erp-hero-stats {\n                justify-content: center;\n            }\n\n            .erp-hero-visual {\n                display: none;\n            }\n\n            .erp-hero-bg svg {\n                opacity: 0.06;\n                width: 80%;\n                right: -20%;\n            }\n\n            .pain-grid, .products-comparison {\n                grid-template-columns: 1fr;\n                max-width: 600px;\n                margin-left: auto;\n                margin-right: auto;\n            }\n\n            .integration-visual {\n                flex-direction: column;\n            }\n\n            .integration-node {\n                width: auto;\n                height: auto;\n            }\n\n            .integration-arrow {\n                transform: rotate(90deg);\n            }\n\n            .boi-callout-grid {\n                grid-template-columns: 1fr !important;\n                text-align: center;\n            }\n\n            .boi-callout-grid > div:first-child {\n                text-align: center;\n            }\n\n            .erpii-modules-grid {\n                grid-template-columns: repeat(2, 1fr);\n            }\n\n            .erp-trust-callout {\n                flex-direction: column;\n            }\n        }\n@media (max-width: 640px) {\n            .erpii-modules-grid {\n                grid-template-columns: 1fr;\n            }\n\n            .erp-use-case-pills {\n                gap: 8px;\n            }\n\n            .erp-use-case-pill {\n                font-size: 12px;\n                padding: 8px 16px;\n            }\n        }\n@media (p