r-events:none;z-index:1}\n.erp-cta-super-d{position:absolute;top:-5%;right:auto;bottom:auto;left:-5%;width:30%;min-height:30vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;opacity:0.14;pointer-events:none;z-index:0}\n.erp-cta-wave-flow{position:absolute;bottom:0;left:0;right:0;height:180px;background:linear-gradient(180deg,transparent,rgba(0,60,200,0.15));opacity:0.35;z-index:1;pointer-events:none}\n.erp-cta-container{position:relative;z-index:3;max-width:700px;margin:0 auto;text-align:center}\n.erp-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.erp-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .erp-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .erp-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .erp-cta-container p{padding-bottom:0 !important}\n\n.erp-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.erp-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.erp-cta-btn:hover::before{left:100%}\n.erp-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.erp-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.erp-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.erp-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.erp-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.erp-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .erp-cta-title{font-size:28px;margin-bottom:16px}\n  .erp-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .erp-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .erp-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.erp-cta-btn{transition:none !important}.erp-cta-btn::before{display:none}}\n\n.et_pb_section:has(.erp-related-section){background:#F5F7FA;padding:0}\n.erp-related-section{padding:60px 5%;background:#F5F7FA;max-width:100%;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\n.erp-related-heading{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:600;color:#000864;margin:0 0 32px 0;padding:0;text-align:center;line-height:1.6;-webkit-font-smoothing:auto}\n.erp-related-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:24px;max-width:1200px;margin:0 auto}\n.erp-related-card{display:block;padding:24px;background:#fff;border-radius:12px;text-decoration:none;border:1px solid #e5e7eb;transition:box-shadow 0.3s ease;color:#333;line-height:1.6}\n.erp-related-card:hover{box-shadow:0 8px 24px rgba(0,8,100,0.1)}\n.erp-related-card-title{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px 0;padding:0;line-height:1.6;-webkit-font-smoothing:auto}\n.erp-related-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#666;margin:0;padding:0;line-height:1.5;-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){.erp-related-card{transition:none}}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="erp-hero">\n    <div class="erp-super-d" aria-hidden="true"></div>\n\n            <div class="erp-hero-bg">\n                <svg aria-hidden="true" viewBox="0 0 600 500" fill="none">\n\n                    <rect x="50" y="50" width="500" height="350" rx="12" stroke="#0369a1" stroke-width="1.5" opacity="0.4"/>\n                    <line x1="50" y1="100" x2="550" y2="100" stroke="#0369a1" stroke-width="1" opacity="0.3"/>\n                    <line x1="150" y1="100" x2="150" y2="400" stroke="#0369a1" stroke-width="1" opacity="0.2"/>\n                    <line x1="300" y1="100" x2="300" y2="400" stroke="#0369a1" stroke-width="1" opacity="0.2"/>\n                    <line x1="450" y1="100" x2="450" y2="400" stroke="#0369a1" stroke-width="1" opacity="0.2"/>\n\n                    <line x1="50" y1="160" x2="550" y2="160" stroke="#0369a1" stroke-width="1" opacity="0.15"/>\n                    <line x1="50" y1="220" x2="550" y2="220" stroke="#0369a1" stroke-width="1" opacity="0.15"/>\n                    <line x1="50" y1="280" x2="550" y2="280" stroke="#0369a1" stroke-width="1" opacity="0.15"/>\n                    <line x1="50" y1="340" x2="550" y2="340" stroke="#0369a1" stroke-width="1" opacity="0.15"/>\n\n                    <rect x="60" y="60" width="80" height="30" rx="4" fill="#0369a1" opacity="0.15"/>\n                    <rect x="160" y="60" width="130" height="30" rx="4" fill="#0369a1" opacity="0.1"/>\n                    <rect x="310" y="60" width="130" height="30" rx="4" fill="#0369a1" opacity="0.1"/>\n                    <rect x="460" y="60" width="80" height="30" rx="4" fill="#0369a1" opacity="0.1"/>\n\n                    <rect x="310" y="165" width="80" height="20" rx="4" fill="#10b981" opacity="0.3"/>\n                    <rect x="460" y="225" width="60" height="20" rx="4" fill="#0369a1" opacity="0.3"/>\n                </svg>\n            </div>\n\n            <div class="erp-hero-inner">\n                <div class="erp-hero-content">\n                    <div class="erp-hero-badge">Core System • ERP</div>\n                    <h1>ทีมบัญชีของคุณ สมควรได้ดีกว่า<span class="highlight">ค่าใช้จ่ายปิดเดือนที่คาดเดาไม่ได้</span></h1>\n                    <p class="erp-hero-subtitle">เห็นต้นทุนจริงแบบ Real-time รายการวัสดุ (BOM) ที่แม่นยำ สินค้าคงคลังที่ตรงกับความจริง ERP (ระบบบริหารทรัพยากรองค์กร) ที่ออกแบบมาเพื่อการผลิตจริงๆ—ไม่ใช่แค่ตามจินตนาการของนักบัญชี</p>\n                    <div class="erp-hero-ctas">\n                        <a href="../demo/" class="btn-white">พูดคุยกับเรา</a>\n                        <a href="#products" class="btn-outline-white">เปรียบเทียบ T100 กับ iGP</a>\n                    </div>\n                    <div class="erp-hero-stats">\n                        <div class="erp-hero-stat">\n                            <div class="erp-hero-stat-number dw-years">44</div>\n                            <div class="erp-hero-stat-label">ปีในอุตฯ การผลิต</div>\n                        </div>\n                        <div class="erp-hero-stat">\n                            <div class="erp-hero-stat-number">50K+</div>\n                            <div class="erp-hero-stat-label">โรงงาน</div>\n                        </div>\n                        <div class="erp-hero-stat">\n                            <div class="erp-hero-stat-number">100+</div>\n                            <div class="erp-hero-stat-label">ไซต์ในไทย</div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class="erp-hero-visual">\n                    <div class="erp-dashboard-mockup">\n                        <div class="mockup-header">\n                            <div class="mockup-dot"></div>\n                            <div class="mockup-dot"></div>\n                            <div class="mockup-dot"></div>\n                        </div>\n                        <div class="mockup-content">\n                            <div class="mockup-nav">\n                                <span class="mockup-nav-item active">แดชบอร์ด</span>\n                                <span class="mockup-nav-item">การผลิต</span>\n                                <span class="mockup-nav-item">คลังสินค้า</span>\n                                <span class="mockup-nav-item">การเงิน</span>\n                            </div>\n                            <div class="mockup-grid">\n                                <div class="mockup-card">\n                                    <div class="mockup-card-label">ผลผลิตวันนี้</div>\n                                    <div class="mockup-card-value green">1,247</div>\n                                </div>\n                                <div class="mockup-card">\n                                    <div class="mockup-card-label">ออเดอร์รอดำเนินการ</div>\n                                    <div class="mockup-card-value">38</div>\n                                </div>\n                                <div class="mockup-card">\n                                    <div class="mockup-card-label">มาร์จิน</div>\n                                    <div class="mockup-card-value blue">24.3%</div>\n                                </div>\n                            </div>\n                            <div class="mockup-chart">\n                                <div class="mockup-bar" style="height: 45%;"></div>\n                                <div class="mockup-bar" style="height: 62%;"></div>\n                                <div class="mockup-bar" style="height: 78%;"></div>\n                                <div class="mockup-bar" style="height: 55%;"></div>\n                                <div class="mockup-bar" style="height: 90%;"></div>\n                                <div class="mockup-bar" style="height: 72%;"></div>\n                                <div class="mockup-bar" style="height: 85%;"></div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-section erp-whatis-section" style="padding: 40px 0 0; text-align: center;">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n        <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 22px; font-weight: 700; color: #000864; margin-bottom: 12px; line-height: 1.6; -webkit-font-smoothing: auto;">ERP (ระบบบริหารทรัพยากรองค์กร) คืออะไร?</h2>\n        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.8; color: #333;">\n          <strong>DigiWin ERP</strong> คือระบบ ERP เฉพาะทางสำหรับโรงงานผลิต ที่เติบโตมาจากประสบการณ์กว่า 44 ปี ในการให้บริการโรงงานทั่วไต้หวัน จีน และเอเชียตะวันออกเฉียงใต้—ภูมิภาคที่การผลิตไม่ใช่แค่อุตสาหกรรม แต่เป็นหัวใจของเศรษฐกิจ มีให้เลือก 2 รุ่น—<strong>T100</strong> สำหรับองค์กรขนาดใหญ่ที่มีหลายโรงงาน (พนักงาน 200+ คน) และ <strong>iGP</strong> สำหรับโรงงานที่กำลังเติบโต (พนักงาน 20–200 คน)—ให้การควบคุมการเงินแบบ Real-time, การจัดการ BOM (รายการวัสดุ), MRP (การวางแผนความต้องการวัสดุ) และ LRP (การวางแผนความต้องการตามล็อต), การจัดการคุณภาพ และการตรวจสอบย้อนกลับการผลิตอย่างครบถ้วน ด้วยลูกค้าโรงงานกว่า 50,000+ ราย และวิศวกร R&amp;D กว่า 1,500+ คน DigiWin เป็นระบบ ERP สำหรับการผลิตที่มีการติดตั้งมากที่สุดในจีนและเอเชียตะวันออกเฉียงใต้—และตอนนี้ให้บริการผู้ผลิตไทยโดยตรงพร้อมทีมงานในประเทศ\n        </p>\n      </div>    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pain (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pain (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pain (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pain-section">\n    <div class="pain-inner">\n                <div class="pain-header">\n                    <p class="pain-label">ฟังดูคุ้นไหม?</p>\n                    <h2 class="pain-title">ปัญหาโรงงานผลิต แก้ได้จริง</h2>\n                    <p class="pain-subtitle">ERP ทั่วไปไม่ได้ถูกสร้างมาเพื่อโรงงาน ปัญหาเหล่านี้จะหมดไปเมื่อระบบของคุณเข้าใจการผลิต</p>\n                </div>\n\n                <div class="pain-grid">\n                    <div class="pain-card">\n                        <div class="pain-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>\n                        </div>\n                        <div class="pain-card-problem">\n                            <p class="pain-card-label problem">ปัญหา</p>\n                            <h3 class="pain-card-title">“เราไม่รู้ต้นทุนจริงจนกว่าจะปิดเดือน”</h3>\n                            <p class="pain-card-desc">ความแตกต่างระหว่างต้นทุนมาตรฐานกับต้นทุนจริงถูกฝังอยู่ในรายการบัญชี เศษวัสดุถูกค้นพบหลังผลิตไปแล้วหลายสัปดาห์ ไม่มีการมองเห็นมาร์จินแบบ Real-time</p>\n                        </div>\n                        <div class="pain-card-solution">\n                            <p class="pain-card-label solution">โซลูชัน DigiWin</p>\n                            <h4 class="pain-card-solution-title">เห็นต้นทุนจริงแบบ Real-Time</h4>\n                            <p class="pain-card-desc">คำนวณต้นทุนจริงในทุกขั้นตอนการผลิต เห็นมาร์จินก่อนส่งของ—ไม่ใช่หลังออกใบแจ้งหนี้</p>\n                        </div>\n                    </div>\n\n                    <div class="pain-card">\n                        <div class="pain-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/><polyline points="10 9 9 9 8 9"/></svg>\n                        </div>\n                        <div class="pain-card-problem">\n                            <p class="pain-card-label problem">ปัญหา</p>\n                            <h3 class="pain-card-title">“MRP ให้ผลลัพธ์ผิดเพราะ BOM ไม่อัพเดท”</h3>\n                            <p class="pain-card-desc">การเปลี่ยนแปลงทางวิศวกรรมเกิดบนสายการผลิต ไม่ใช่ในระบบ เวอร์ชัน BOM กระจัดกระจายอยู่ใน Spreadsheet</p>\n                        </div>\n                        <div class="pain-card-solution">\n                            <p class="pain-card-label solution">โซลูชัน DigiWin</p>\n                            <h4 class="pain-card-solution-title">ระบบควบคุมการเปลี่ยนแปลงทางวิศวกรรม</h4>\n                            <p class="pain-card-desc">กระบวนการ ECN (Engineering Change Notice) ทำให้มั่นใจว่าการเปลี่ยนแปลงถูกบันทึกก่อนผลิต MRP รันจาก BOM ที่เป็นปัจจุบันและอนุมัติแล้วเสมอ</p>\n                        </div>\n                    </div>\n\n                    <div class="pain-card">\n                        <div class="pain-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.27 6.96 12 12.01 20.73 6.96"/><line x1="12" y1="22.08" x2="12" y2="12"/></svg>\n                        </div>\n                        <div class="pain-card-problem">\n                            <p class="pain-card-label problem">ปัญหา</p>\n                            <h3 class="pain-card-title">“สินค้าคงคลังนับจริง ไม่ตรงกับระบบ”</h3>\n                            <p class="pain-card-desc">สินค้าผีตามหลอกทุกการตรวจสอบ การผลิตใช้วัสดุที่ไม่มีอยู่จริง จัดซื้อสั่งซ้ำของที่มีอยู่แล้ว</p>\n                        </div>\n                        <div class="pain-card-solution">\n                            <p class="pain-card-label solution">โซลูชัน DigiWin</p>\n                            <h4 class="pain-card-solution-title">ความถูกต้องระดับทุกรายการเคลื่อนไหว</h4>\n                            <p class="pain-card-desc">บันทึกทุกการเคลื่อนไหวของวัสดุที่ต้นทาง สแกนบาร์โค้ดบังคับใช้ที่จุดสำคัญ การนับวนรอบ (Cycle Counting) ติดตั้งในตัว</p>\n                        </div>\n                    </div>\n\n                    <div class="pain-card">\n                        <div class="pain-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/><path d="M11 8v6M8 11h6"/></svg>\n                        </div>\n                        <div class="pain-card-problem">\n                            <p class="pain-card-label problem">ปัญหา</p>\n                            <h3 class="pain-card-title">“เราตามหาต้นตอปัญหาคุณภาพไม่ได้”</h3>\n                            <p class="pain-card-desc">ลูกค้าร้องเรียนแล้วต้องตามหาอย่างร้อนรน เลขล็อตอยู่ที่ไหนสักแห่ง อาจจะ... การวิเคราะห์สาเหตุใช้เวลาเป็นสัปดาห์</p>\n                        </div>\n                        <div class="pain-card-solution">\n                            <p class="pain-card-label solution">โซลูชัน DigiWin</p>\n                            <h4 class="pain-card-solution-title">ตรวจสอบย้อนกลับได้ครบวงจร</h4>\n                            <p class="pain-card-desc">ติดตามล็อตตั้งแต่รับเข้าจนถึงจัดส่ง คลิกเดียวเห็นประวัติทั้งหมด ข้อมูลคุณภาพเชื่อมโยงกับล็อต เครื่องจักร และพนักงาน</p>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="products-section">\n    <div class="products-inner">\n                <div class="products-header">\n                    <p class="products-label">เลือกขนาดที่เหมาะสม</p>\n                    <h2 class="products-title">สอง ERP หนึ่งปรัชญา</h2>\n                    <p class="products-subtitle">ออกแบบเพื่อการผลิตเป็นอันดับแรก เติบโตไปพร้อมกับธุรกิจของคุณ เริ่มจากจุดที่คุณอยู่ ขยายเมื่อพร้อม</p>\n                </div>\n\n                <nav class="erp-use-case-pills" aria-label="ERP use cases">\n                    <a href="#igp-card" class="erp-use-case-pill">Warehouse ERP</a>\n                    <a href="#t100-card" class="erp-use-case-pill">Smart Factory</a>\n                    <a href="#igp-card" class="erp-use-case-pill">Cloud ERP</a>\n                    <a href="#capabilities" class="erp-use-case-pill">Financial</a>\n                    <a href="#t100-card" class="erp-use-case-pill">Custom Solutions</a>\n                </nav>\n\n                <div class="products-comparison">\n\n                    <div class="product-card" id="t100-card">\n                        <div class="product-card-header">\n                            <span class="product-card-badge">ระดับองค์กร</span>\n                            <h3 class="product-card-name">T100</h3>\n                            <p class="product-card-tagline">ERP เต็มรูปแบบสำหรับการดำเนินงานที่ซับซ้อน</p>\n                        </div>\n                        <div class="product-card-body">\n                            <p class="product-card-desc">หลายโรงงาน หลายสกุลเงิน หลายบริษัท—สร้างมาเพื่อองค์กรที่ต้องการการควบคุมเต็มรูปแบบในการดำเนินงานที่ซับซ้อนและกระจายตัว</p>\n                            <ul class="product-features">\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> รวมงบการเงินหลายบริษัท</li>\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> รายงานการเงินขั้นสูง</li>\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> BOM ซับซ้อนพร้อมระบบควบคุมการเปลี่ยนแปลงวิศวกรรม</li>\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> ระบบ Workflow สำหรับองค์กร</li>\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> MRP ขั้นสูง และการจัดตารางการผลิต</li>\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> แดชบอร์ด Business Intelligence ในตัว</li>\n                            </ul>\n                            <div class="product-best-for">\n                                <div class="product-best-for-label">เหมาะสำหรับ</div>\n                                <div class="product-best-for-text">พนักงาน 200+ คน หลายโรงงาน ซัพพลายเชนซับซ้อน กลุ่มบริษัทที่ต้องการรวมงบ</div>\n                            </div>\n\n                            <div class="erp-trust-callout">\n                                <div class="erp-trust-icon">\n                                    <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="5" y="11" width="14" height="10" rx="2"/><path d="M12 3a4 4 0 0 0-4 4v4h8V7a4 4 0 0 0-4-4z"/><path d="M8 7v4M16 7v4"/><circle cx="12" cy="16" r="1"/><path d="M12 17v2"/></svg>\n                                </div>\n                                <div>\n                                    <h4 class="erp-trust-title">ข้อมูลของคุณ เป็นของคุณ</h4>\n                                    <p class="erp-trust-body">รวมการโอนซอร์สโค้ดทั้งหมด ระบบของคุณ ข้อมูลของคุณ ความเป็นอิสระของคุณ—ไม่มีการผูกมัดกับผู้ขาย ตลอดไป พร้อมบริการ e-Service และ e-Learning ตลอด 24 ชั่วโมง</p>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n\n                    <div class="product-card" id="igp-card">\n                        <div class="product-card-header">\n                            <span class="product-card-badge">ช่วงเติบโต</span>\n                            <h3 class="product-card-name">iGP</h3>\n                            <p class="product-card-tagline">ขนาดพอดีสำหรับโรงงานที่กำลังเติบโต</p>\n                        </div>\n                        <div class="product-card-body">\n                            <p class="product-card-desc">ฟีเจอร์เฉพาะทางการผลิตครบทุกอย่างที่ต้องการ โดยไม่ต้องแบกความซับซ้อนขององค์กรใหญ่ ติดตั้งเร็ว ใช้งานง่าย</p>\n                            <ul class="product-features">\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> ระบบบัญชีการเงินและคลังสินค้าครบถ้วน</li>\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> วางแผนการผลิตและ MRP</li>\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> จัดการคุณภาพ</li>\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> จัดซื้อจัดจ้างและขาย</li>\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> แดชบอร์ดมาตรฐาน</li>\n                                <li><span class="check-icon"><svg aria-hidden="true" viewBox="0 0 12 12"><path d="M2 6l3 3 5-5"/></svg></span> ติดตั้งรวดเร็ว</li>\n                            </ul>\n                            <div class="product-best-for">\n                                <div class="product-best-for-label">เหมาะสำหรับ</div>\n                                <div class="product-best-for-text">พนักงาน 20–200 คน โรงงานเดียว การดำเนินงานตรงไปตรงมา ก้าวข้าม Spreadsheet</div>\n                            </div>\n\n                            <p class="erp-proven-in">พิสูจน์แล้วในอุตสาหกรรมชิ้นส่วนยานยนต์ แปรรูปอาหาร อิเล็กทรอนิกส์ เครื่องจักรกล สกรู ยางและพลาสติก สิ่งทอ และอุตสาหกรรมการผลิตอื่นๆ อีกมากมาย</p>\n\n                            <details class="erp-erpii-accordion">\n                                <summary>iGP มากกว่าแค่ ERP <span class="accordion-icon" aria-hidden="true">+</span></summary>\n                                <div class="erpii-content">\n                                    <h4 class="erpii-title">เริ่มจาก ERP ขยายได้ทุกทิศทาง</h4>\n                                    <p class="erpii-subtitle">iGP เป็นแพลตฟอร์ม ERPII ที่ครบถ้วน เริ่มจากบัญชีและการผลิต แล้วเพิ่มโมดูลเมื่อเติบโต—ไม่ต้องเปลี่ยนระบบ</p>\n                                    <div class="erpii-modules-grid">\n                                        <div class="erpii-module-card">\n                                            <div class="erpii-module-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18M9 21V9"/></svg></div>\n                                            <div class="erpii-module-label">BI / KPI</div>\n                                            <div class="erpii-module-name">Business Intelligence</div>\n                                            <div class="erpii-module-desc">แดชบอร์ดผู้บริหารและ Balanced Scorecard</div>\n                                        </div>\n                                        <div class="erpii-module-card">\n                                            <div class="erpii-module-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M16 3h5v5M4 20L21 3M21 16v5h-5M14 14l7 7M3 8V3h5M10 10L3 3"/></svg></div>\n                                            <div class="erpii-module-label">SCM</div>\n                                            <div class="erpii-module-name">ซัพพลายเชน</div>\n                                            <div class="erpii-module-desc">มองเห็นตั้งแต่ซัพพลายเออร์จนถึงลูกค้า</div>\n                                        </div>\n                                        <div class="erpii-module-card">\n                                            <div class="erpii-module-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg></div>\n                                            <div class="erpii-module-label">PLM</div>\n                                            <div class="erpii-module-name">วงจรผลิตภัณฑ์</div>\n                                            <div class="erpii-module-desc">BOM กระบวนการ และแบบร่าง</div>\n                                        </div>\n                                        <div class="erpii-module-card">\n                                            <div class="erpii-module-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="16" rx="2"/><path d="M3 10h18"/><path d="M8 2v4M16 2v4"/></svg></div>\n                                            <div class="erpii-module-label">APS</div>\n                                            <div class="erpii-module-name">วางแผนขั้นสูง</div>\n                                            <div class="erpii-module-desc">จัดตารางตามกำลังการผลิตจริง</div>\n                                        </div>\n                                        <div class="erpii-module-card">\n                                            <div class="erpii-module-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="4" width="20" height="16" rx="2"/><path d="M6 8v8M10 8v8M14 8v8M18 8v8"/></svg></div>\n                                            <div class="erpii-module-label">MES / SFT</div>\n                                            <div class="erpii-module-name"><a href="/products/mes/" style="color: inherit; text-decoration: underline; text-decoration-color: #0369a1; text-underline-offset: 2px;">สายการผลิต</a></div>\n                                            <div class="erpii-module-desc">ติดตามการผลิตแบบ Real-time</div>\n                                        </div>\n                                        <div class="erpii-module-card">\n                                            <div class="erpii-module-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg></div>\n                                            <div class="erpii-module-label">CRM</div>\n                                            <div class="erpii-module-name">จัดการลูกค้า</div>\n                                            <div class="erpii-module-desc">จากใบเสนอราคาถึงคำสั่งซื้อถึงความสัมพันธ์</div>\n                                        </div>\n                                    </div>\n                                </div>\n                            </details>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="capabilities-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <circle cx="700" cy="450" r="70" stroke="#000864" stroke-width="2" fill="none" opacity="0.12"/>\n                    <circle cx="700" cy="450" r="35" stroke="#0369a1" stroke-width="1.5" fill="none" opacity="0.1"/>\n                    <text x="700" y="455" font-family="\'Noto Sans\',sans-serif" font-size="14" font-weight="700" fill="#000864" opacity="0.1" text-anchor="middle">ERP</text>\n                    <rect x="100" y="200" width="90" height="60" rx="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <text x="145" y="235" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">FINANCE</text>\n                    <line x1="190" y1="230" x2="635" y2="430" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <rect x="100" y="600" width="90" height="60" rx="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <text x="145" y="635" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">INVENTORY</text>\n                    <line x1="190" y1="630" x2="635" y2="470" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <rect x="1210" y="200" width="90" height="60" rx="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <text x="1255" y="235" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">SALES</text>\n                    <line x1="1210" y1="230" x2="765" y2="430" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <rect x="1210" y="600" width="90" height="60" rx="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <text x="1255" y="635" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">PURCHASE</text>\n                    <line x1="1210" y1="630" x2="765" y2="470" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <path d="M450 320 L460 330 L480 310" stroke="#0369a1" stroke-width="2" fill="none" opacity="0.18"/>\n                    <path d="M920 320 L930 330 L950 310" stroke="#0369a1" stroke-width="2" fill="none" opacity="0.18"/>\n                    <circle cx="350" cy="450" r="3" fill="#000864" opacity="0.1"/>\n                    <circle cx="1050" cy="450" r="3" fill="#000864" opacity="0.1"/>\n                </svg>\n            </div>\n            <div class="capabilities-inner" style="position: relative; z-index: 2;">\n                <div class="capabilities-header">\n                    <p class="capabilities-label">มีอะไรอยู่ข้างใน</p>\n                    <h2 class="capabilities-title">ความสามารถหลักของ ERP</h2>\n                </div>\n\n                <div class="capabilities-grid">\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg></div>\n                        <h3 class="capability-title">ควบคุมการเงิน</h3>\n                        <p class="capability-desc">หลายสกุลเงิน หลายบริษัท เห็นต้นทุนจริงแบบ Real-time รวมงบอัตโนมัติ</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><path d="M3.27 6.96L12 12.01l8.73-5.05M12 22.08V12"/></svg></div>\n                        <h3 class="capability-title">จัดการคลังสินค้า</h3>\n                        <p class="capability-desc">ติดตามล็อต หลายคลัง นับวนรอบ ระบบ Min/Max อัตโนมัติ</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="4" width="20" height="16" rx="2"/><path d="M6 8v8M10 8v8M14 8v8M18 8v8"/></svg></div>\n                        <h3 class="capability-title">วางแผนการผลิต</h3>\n                        <p class="capability-desc">ระบบ MRP (การวางแผนความต้องการวัสดุ) พร้อมจัดตารางขั้นสูง วางแผนกำลังการผลิต ปล่อยใบสั่งผลิต จัดตารางให้เหมาะสม</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M9 12l2 2 4-4"/><circle cx="12" cy="12" r="10"/></svg></div>\n                        <h3 class="capability-title">จัดการคุณภาพ</h3>\n                        <p class="capability-desc">ตรวจสอบคุณภาพขาเข้า ขาออก และระหว่างกระบวนการ ติดตามความไม่สอดคล้อง จัดการแก้ไข พร้อมเชื่อมต่อ SPC (การควบคุมกระบวนการทางสถิติ)</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z"/><line x1="3" y1="6" x2="21" y2="6"/><path d="M16 10a4 4 0 0 1-8 0"/></svg></div>\n                        <h3 class="capability-title">จัดซื้อจัดจ้าง</h3>\n                        <p class="capability-desc">จัดการซัพพลายเออร์ กระบวนการ RFQ/PO ใบสั่งซื้อแบบกรอบ ตรวจรับสินค้า</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M3 3v18h18"/><path d="M18.7 8l-5.1 5.2-2.8-2.7L7 14.3"/></svg></div>\n                        <h3 class="capability-title">ขาย & CRM</h3>\n                        <p class="capability-desc">จากใบเสนอราคาถึงคำสั่งซื้อ ตรวจสอบสินค้าพร้อมส่ง ควบคุมเครดิตลูกค้า จัดตารางจัดส่ง</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18M9 21V9"/></svg></div>\n                        <h3 class="capability-title">รายงาน & BI</h3>\n                        <p class="capability-desc">รายงานสำหรับการผลิตสำเร็จรูป แดชบอร์ดปรับแต่งได้ ส่งออก Excel เข้าถึงผ่านมือถือ</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83"/></svg></div>\n                        <h3 class="capability-title">การเชื่อมต่อ</h3>\n                        <p class="capability-desc">เชื่อมต่อ MES/WMS/AIoT แบบ Native API สำหรับระบบภายนอก EDI สำหรับลูกค้า</p>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 6 (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 6 (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 6 (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="tech-advantages-section"><div style="max-width: 1200px; margin: 0 auto; padding: 0 24px;">\n                <div style="text-align: center; margin-bottom: 60px;">\n                    <p style="font-family: \'JetBrains Mono\', monospace; font-size: 13px; font-weight: 500; text-transform: uppercase; letter-spacing: 0.1em; color: #0369a1; margin-bottom: 12px;">สิ่งที่ทำให้ DigiWin แตกต่าง</p>\n                    <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 700; color: #000864; margin-bottom: 16px;">7 ข้อได้เปรียบทางเทคนิค สร้างมาเพื่อโรงงานจริง</h2>\n                    <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 18px; color: #666; max-width: 700px; margin: 0 auto;">นี่ไม่ใช่ฟีเจอร์เล็กๆ—แต่เป็นขีดความสามารถเชิงสถาปัตยกรรมพื้นฐาน ที่ตอบโจทย์ความท้าทายในโรงงานผลิตไทยอย่างแท้จริง</p>\n                </div>\n\n                <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(340px, 1fr)); gap: 24px;">\n\n                    <div class="weapon-card" style="background: #fff; border: 1px solid #e8eef3; border-radius: 20px; padding: 32px; transition: all 0.4s ease; position: relative;">\n                        <div style="display: flex; align-items: center; gap: 12px; margin-bottom: 16px;">\n                            <div style="width: 48px; height: 48px; background: linear-gradient(135deg, rgba(3,105,161,0.15), rgba(3,105,161,0.05)); border-radius: 12px; display: flex; align-items: center; justify-content: center;">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="#0369a1" stroke-width="1.5" style="width: 24px; height: 24px;"><path d="M3 3v18h18"/><path d="M7 16l4-8 4 4 5-9"/><circle cx="20" cy="3" r="1.5" fill="#0369a1" stroke="none"/></svg>\n                            </div>\n                            <div>\n                                <h3 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 18px; font-weight: 600; color: #000864; margin: 0;">การวางแผนวัสดุขั้นสูง</h3>\n                                <p style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; color: #0369a1; text-transform: uppercase; letter-spacing: 0.05em; margin: 2px 0 0;">AMRP</p>\n                            </div>\n                        </div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; color: #333; line-height: 1.7; margin-bottom: 12px;">วางแผนกำลังการผลิตในตัว ERP จัดตารางผลิตตามกำลังเครื่องจักร วัสดุที่มี และแรงงานจริง—คำนวณทั้งหมดในระบบเดียว</p>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 14px; color: #0369a1; font-weight: 500;">ระบบ ERP ระดับองค์กรหลายค่ายต้องซื้อระบบ APS (การวางแผนขั้นสูง) แยกต่างหาก</p>\n                    </div>\n\n                    <div class="weapon-card" style="background: #fff; border: 1px solid #e8eef3; border-radius: 20px; padding: 32px; transition: all 0.4s ease; position: relative;">\n                        <div style="display: flex; align-items: center; gap: 12px; margin-bottom: 16px;">\n                            <div style="width: 48px; height: 48px; background: linear-gradient(135deg, rgba(3,105,161,0.15), rgba(3,105,161,0.05)); border-radius: 12px; display: flex; align-items: center; justify-content: center;">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="#0369a1" stroke-width="1.5" style="width: 24px; height: 24px;"><path d="M12 3v6"/><path d="M12 9l-7 6"/><path d="M12 9l7 6"/><circle cx="12" cy="3" r="2"/><circle cx="5" cy="17" r="2"/><circle cx="19" cy="17" r="2"/></svg>\n                            </div>\n                            <div>\n                                <h3 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 18px; font-weight: 600; color: #000864; margin: 0;">การบัญชีผลิตภัณฑ์ร่วม</h3>\n                                <p style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; color: #0369a1; text-transform: uppercase; letter-spacing: 0.05em; margin: 2px 0 0;">Multi-Output Work Orders</p>\n                            </div>\n                        </div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; color: #333; line-height: 1.7; margin-bottom: 12px;">ใบสั่งผลิตเดียวสร้างผลผลิตหลายรายการ จัดสรรต้นทุนแม่นยำต่อผลิตภัณฑ์ จำเป็นสำหรับอุตสาหกรรมฉีดพลาสติก แปรรูปอาหาร และเคมีภัณฑ์</p>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 14px; color: #0369a1; font-weight: 500;">ระบบ ERP คู่แข่งส่วนใหญ่ไม่รองรับใบสั่งผลิตผลิตภัณฑ์ร่วมโดยไม่ต้อง Customize ราคาแพง</p>\n                    </div>\n\n                    <div class="weapon-card" style="background: #fff; border: 1px solid #e8eef3; border-radius: 20px; padding: 32px; transition: all 0.4s ease; position: relative;">\n                        <div style="display: flex; align-items: center; gap: 12px; margin-bottom: 16px;">\n                            <div style="width: 48px; height: 48px; background: linear-gradient(135deg, rgba(3,105,161,0.15), rgba(3,105,161,0.05)); border-radius: 12px; display: flex; align-items: center; justify-content: center;">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="#0369a1" stroke-width="1.5" style="width: 24px; height: 24px;"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/></svg>\n                            </div>\n                            <div>\n                                <h3 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 18px; font-weight: 600; color: #000864; margin: 0;">การวางแผนความต้องการตามล็อต</h3>\n                                <p style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; color: #0369a1; text-transform: uppercase; letter-spacing: 0.05em; margin: 2px 0 0;">LRP</p>\n                            </div>\n                        </div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; color: #333; line-height: 1.7; margin-bottom: 12px;">คำนวณความต้องการวัสดุสำหรับใบสั่งผลิตเฉพาะได้ภายในไม่ถึงนาที ไม่ต้องรอรัน MRP เต็มรูปแบบหลายชั่วโมงเพื่อตอบคำถาม "รับออเดอร์นี้ได้ไหม?"</p>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 14px; color: #0369a1; font-weight: 500;">รับหรือปฏิเสธออเดอร์ได้อย่างมั่นใจ—ขณะที่ลูกค้ายังอยู่สายโทรศัพท์</p>\n                    </div>\n\n                    <div class="weapon-card" style="background: #fff; border: 1px solid #e8eef3; border-radius: 20px; padding: 32px; transition: all 0.4s ease; position: relative;">\n                        <div style="display: flex; align-items: center; gap: 12px; margin-bottom: 16px;">\n                            <div style="width: 48px; height: 48px; background: linear-gradient(135deg, rgba(3,105,161,0.15), rgba(3,105,161,0.05)); border-radius: 12px; display: flex; align-items: center; justify-content: center;">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="#0369a1" stroke-width="1.5" style="width: 24px; height: 24px;"><path d="M12 3v18"/><path d="M3 12l3-3v6l-3-3z" fill="#0369a1" stroke="none"/><path d="M21 12l-3-3v6l3-3z" fill="#0369a1" stroke="none"/><rect x="6" y="6" width="4" height="12" rx="1" opacity="0.3" fill="#0369a1" stroke="none"/><rect x="14" y="4" width="4" height="16" rx="1" opacity="0.3" fill="#0369a1" stroke="none"/></svg>\n                            </div>\n                            <div>\n                                <h3 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 18px; font-weight: 600; color: #000864; margin: 0;">ติดตามสองหน่วยพร้อมกัน</h3>\n                                <p style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; color: #0369a1; text-transform: uppercase; letter-spacing: 0.05em; margin: 2px 0 0;">Simultaneous UOM Display</p>\n                            </div>\n                        </div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; color: #333; line-height: 1.7; margin-bottom: 12px;">แสดงและติดตามทั้งน้ำหนัก (กก.) และจำนวน (ชิ้น) พร้อมกันในทุกรายการ ไม่ต้องแปลง ไม่มีข้อผิดพลาดจากการปัดเศษ ไม่สับสน</p>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 14px; color: #0369a1; font-weight: 500;">ระบบ ERP ระดับกลางส่วนใหญ่แสดงหน่วยวัดได้ครั้งละหน่วยเดียวเท่านั้น</p>\n                    </div>\n\n                    <div class="weapon-card" style="background: #fff; border: 1px solid #e8eef3; border-radius: 20px; padding: 32px; transition: all 0.4s ease; position: relative;">\n                        <div style="display: flex; align-items: center; gap: 12px; margin-bottom: 16px;">\n                            <div style="width: 48px; height: 48px; background: linear-gradient(135deg, rgba(3,105,161,0.15), rgba(3,105,161,0.05)); border-radius: 12px; display: flex; align-items: center; justify-content: center;">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="#0369a1" stroke-width="1.5" style="width: 24px; height: 24px;"><rect x="3" y="4" width="18" height="16" rx="2"/><path d="M3 10h18"/><path d="M8 2v4M16 2v4"/><rect x="6" y="13" width="3" height="2" rx="0.5" fill="#0369a1" stroke="none"/><rect x="11" y="13" width="3" height="2" rx="0.5" fill="#0369a1" stroke="none" opacity="0.5"/><rect x="16" y="13" width="3" height="2" rx="0.5" fill="#0369a1" stroke="none" opacity="0.3"/></svg>\n                            </div>\n                            <div>\n                                <h3 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 18px; font-weight: 600; color: #000864; margin: 0;">จัดตารางย่อยบนสายการผลิต</h3>\n                                <p style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; color: #0369a1; text-transform: uppercase; letter-spacing: 0.05em; margin: 2px 0 0;">Real-Time Floor Adjustments</p>\n                            </div>\n                        </div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; color: #333; line-height: 1.7; margin-bottom: 12px;">หัวหน้าสายปรับตารางการผลิตแบบ Real-time และการเปลี่ยนแปลงจะมองเห็นทันทีที่ฝ่ายวางแผน เชื่อมช่องว่างระหว่างแผนกับความจริง</p>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 14px; color: #0369a1; font-weight: 500;">การเชื่อมต่อแบบสองทิศทางจากสายการผลิตถึงฝ่ายวางแผนนี้หาได้ยากใน ERP ระดับกลาง</p>\n                    </div>\n\n                    <div class="weapon-card" style="background: #fff; border: 1px solid #e8eef3; border-radius: 20px; padding: 32px; transition: all 0.4s ease; position: relative;">\n                        <div style="display: flex; align-items: center; gap: 12px; margin-bottom: 16px;">\n                            <div style="width: 48px; height: 48px; background: linear-gradient(135deg, rgba(3,105,161,0.15), rgba(3,105,161,0.05)); border-radius: 12px; display: flex; align-items: center; justify-content: center;">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="#0369a1" stroke-width="1.5" style="width: 24px; height: 24px;"><path d="M20.59 13.41l-7.17 7.17a2 2 0 0 1-2.83 0L2 12V2h10l8.59 8.59a2 2 0 0 1 0 2.82z"/><circle cx="7" cy="7" r="1.5" fill="#0369a1" stroke="none"/></svg>\n                            </div>\n                            <div>\n                                <h3 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 18px; font-weight: 600; color: #000864; margin: 0;">รหัสคุณลักษณะ</h3>\n                                <p style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; color: #0369a1; text-transform: uppercase; letter-spacing: 0.05em; margin: 2px 0 0;">Multi-Dimension Variants</p>\n                            </div>\n                        </div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; color: #333; line-height: 1.7; margin-bottom: 12px;">จัดการสินค้าที่มีหลายรูปแบบได้ถึง 3 มิติ (สี ขนาด เกรด) ภายใต้รหัสสินค้าเดียว เปลี่ยน 27 SKU เป็น 1 ผลิตภัณฑ์ที่จัดการง่าย ตรวจสอบย้อนกลับได้ครบ</p>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 14px; color: #0369a1; font-weight: 500;">ลดความซับซ้อนของ Item Master ได้มากกว่า 90%+ สำหรับผู้ผลิตที่มีสินค้าหลายรูปแบบ</p>\n                    </div>\n\n                    <div class="weapon-card" style="background: #fff; border: 1px solid #e8eef3; border-radius: 20px; padding: 32px; transition: all 0.4s ease; position: relative;">\n                        <div style="display: flex; align-items: center; gap: 12px; margin-bottom: 16px;">\n                            <div style="width: 48px; height: 48px; background: linear-gradient(135deg, rgba(3,105,161,0.15), rgba(3,105,161,0.05)); border-radius: 12px; display: flex; align-items: center; justify-content: center;">\n                                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="#0369a1" stroke-width="1.5" style="width: 24px; height: 24px;"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/><path d="M9 12l2 2 4-4" stroke-width="2"/></svg>\n                            </div>\n                            <div>\n                                <h3 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 18px; font-weight: 600; color: #000864; margin: 0;">กระทบยอด BOI (คณะกรรมการส่งเสริมการลงทุน)</h3>\n                                <p style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; color: #0369a1; text-transform: uppercase; letter-spacing: 0.05em; margin: 2px 0 0;">Production-Order-Level Tracking</p>\n                            </div>\n                        </div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; color: #333; line-height: 1.7; margin-bottom: 12px;">ติดตามการใช้วัสดุจริงในระดับใบสั่งผลิต—ไม่ใช่การคำนวณตามทฤษฎี BOM สร้างรายงาน BOI ที่ตรงกับสิ่งที่คณะกรรมการส่งเสริมการลงทุนตรวจสอบ</p>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 14px; color: #0369a1; font-weight: 500;">ไม่มีคู่แข่งรายใดเสนอการกระทบยอดวัสดุ BOI ในระดับใบสั่งผลิต</p>\n                    </div>\n                </div>\n\n                <div class="boi-callout-grid" style="margin-top: 48px; background: linear-gradient(135deg, #000864, #1e3a5f); border-radius: 20px; padding: 48px; display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: center;">\n                    <div>\n                        <p style="font-family: \'JetBrains Mono\', monospace; font-size: 12px; text-transform: uppercase; letter-spacing: 0.1em; color: #00AFF0; margin-bottom: 12px;">ผลลัพธ์ที่พิสูจน์แล้ว</p>\n                        <h3 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #fff; margin-bottom: 16px;">จาก 10 ล้านบาท/ปี เหลือศูนย์ภาษีเพิ่มเติม</h3>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 17px; color: rgba(255,255,255,0.85); line-height: 1.8;">เมื่อ BOI ตรวจสอบลูกค้าของเรา การกระทบยอดระดับใบสั่งผลิตของ DigiWin แสดงการใช้วัสดุจริง—ไม่มีช่องว่าง ไม่มีการเดา ผลลัพธ์: ภาษีเพิ่มเติมลดจากกว่า 10 ล้านบาทต่อปีเหลือศูนย์</p>\n                        <a href="../boi-compliance-jin-hai/" style="display: inline-flex; align-items: center; gap: 8px; margin-top: 20px; font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 500; color: #00AFF0; text-decoration: none;">อ่านเรื่องราวฉบับเต็ม <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width: 16px; height: 16px;"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n                    </div>\n                    <div style="text-align: center;">\n                        <div style="display: inline-block; background: rgba(0,175,240,0.15); border-radius: 20px; padding: 40px;">\n                            <div style="font-family: \'JetBrains Mono\', monospace; font-size: 56px; font-weight: 700; color: #00AFF0;">10M+</div>\n                            <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; color: rgba(255,255,255,0.75); margin-top: 8px;">บาท/ปี ที่ประหยัดได้</div>\n                            <div style="width: 40px; height: 2px; background: #00AFF0; margin: 16px auto;"></div>\n                            <div style="font-family: \'JetBrains Mono\', monospace; font-size: 56px; font-weight: 700; color: #15803d;">Zero</div>\n                            <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; color: rgba(255,255,255,0.75); margin-top: 8px;">ภาษีเพิ่มเติมใน 2025</div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class="boi-enforcement-alert">\n                    <div class="boi-enforcement-header">\n                        <div class="boi-enforcement-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none">\n                                <path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z" fill="#FFD700" stroke="#b45309" stroke-width="1.5"/>\n                                <line x1="12" y1="9" x2="12" y2="13" stroke="#92400e" stroke-width="2" stroke-linecap="round"/>\n                                <circle cx="12" cy="17" r="1" fill="#92400e"/>\n                            </svg>\n                        </div>\n                        <h3 class="boi-enforcement-title">BOI 2026: การบังคับใช้จริงจังขึ้นแล้ว</h3>\n                    </div>\n                    <p class="boi-enforcement-body">คณะกรรมการส่งเสริมการลงทุนกำลังเข้มงวดใน 4 ด้านที่ส่งผลกระทบโดยตรงต่อโรงงานของคุณ:</p>\n                    <ol class="boi-enforcement-list">\n                        <li>\n                            <span class="boi-num">1</span>\n                            <div><strong>ตรวจจับการทำบัญชีคู่</strong> ระบบแยกสำหรับธุรกรรม BOI กับ non-BOI กำลังถูกตรวจพบ ระบบบูรณาการเดียวขจัดความเสี่ยง</div>\n                        </li>\n                        <li>\n                            <span class="boi-num">2</span>\n                            <div><strong>ตรวจสอบสินค้าคงคลังไม่ตรง</strong> สินค้าจริงกับในระบบไม่ตรงกันทำให้เกิดการตรวจสอบ บาร์โค้ด WMS และ Cycle Counting ให้ความแม่นยำ 95%+</div>\n                        </li>\n                        <li>\n                            <span class="boi-num">3</span>\n                            <div><strong>การจัดประเภทธุรกรรม BOI/non-BOI</strong> จัดประเภทผิดอาจนำไปสู่การเพิกถอนสิทธิประโยชน์ การติดตามระดับใบสั่งผลิตแยก BOI กับ non-BOI อัตโนมัติ</div>\n                        </li>\n                        <li>\n                            <span class="boi-num">4</span>\n                            <div><strong>การเรียกคืนภาษีศุลกากร</strong> การนำเข้าที่ไม่สอดคล้องเผชิญการเรียกเก็บอากรย้อนหลัง Audit trail ครบตั้งแต่รับเข้าถึงจัดส่งให้รายงาน BOI พร้อมเมื่อต้องการ</div>\n                        </li>\n                    </ol>\n                    <a href="../boi-compliance-jin-hai/" class="boi-enforcement-cta">ดูว่า DigiWin ERP จัดการ BOI compliance อย่างไร <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n                    <p class="boi-enforcement-source">อ้างอิงจากแนวโน้มการบังคับใช้ BOI ยืนยันจากสัมมนา compliance ของ DigiWin วันที่ 28 มกราคม 2026</p>\n                </div>\n            </div></div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="integration-section">\n    <div class="dw-d-bg dw-d-bg--left dw-d-bg--medium dw-d-parallax"></div>\n            <div class="integration-inner" style="position: relative; z-index: 2;">\n                <div class="integration-header">\n                    <p class="integration-label">ก้าวข้ามประตูออฟฟิศ</p>\n                    <h2 class="integration-title">ERP ที่เข้าถึงสายการผลิต</h2>\n                    <p class="integration-subtitle">ระบบ ERP ส่วนใหญ่หยุดอยู่แค่ในออฟฟิศ DigiWin เชื่อมต่อตรงถึงเครื่องจักร คลังสินค้า และสายการผลิตของคุณ</p>\n                </div>\n\n                <div class="integration-visual">\n                    <div class="integration-node active">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18M9 21V9"/></svg>\n                        </div>\n                        <div class="integration-node-name">ERP</div>\n                    </div>\n                    <div class="integration-arrow">↔</div>\n                    <div class="integration-node">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="4" width="20" height="16" rx="2"/><path d="M6 8v8M10 8v8M14 8v8M18 8v8"/></svg>\n                        </div>\n                        <div class="integration-node-name">MES</div>\n                    </div>\n                    <div class="integration-arrow">↔</div>\n                    <div class="integration-node">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/></svg>\n                        </div>\n                        <div class="integration-node-name">WMS</div>\n                    </div>\n                    <div class="integration-arrow">↔</div>\n                    <div class="integration-node">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4"/></svg>\n                        </div>\n                        <div class="integration-node-name">AIoT</div>\n                    </div>\n                </div>\n\n                <div class="integration-message">\n                    <p>คลิกเดียวใน ERP ปล่อยใบสั่งผลิตลงสายการผลิต สแกนครั้งเดียวบนสายการผลิตอัพเดทสินค้าคงคลังใน ERP ไม่มีการอัพโหลดแบตช์ ไม่มีการกระทบยอดด้วยมือ <strong>ฐานข้อมูลเดียว ความจริงเดียว</strong></p>\n                </div>\n\n                <div class="integration-links">\n                    <a href="/products/mes/" class="integration-link">สำรวจ MES <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n                    <a href="/products/wms/" class="integration-link">สำรวจ WMS <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n                    <a href="/products/aiot/" class="integration-link">สำรวจ AIoT <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="erp-faq">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n            <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px; text-align: center;">คำถามที่พบบ่อย</h2>\n            <div style="display: flex; flex-direction: column; gap: 12px;">\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">T100 กับ iGP ต่างกันอย่างไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">T100 คือ ERP ระดับองค์กรของ DigiWin ออกแบบสำหรับผู้ผลิตที่มีพนักงาน 200+ คน หลายโรงงาน และโครงสร้างหลายบริษัทที่ซับซ้อน iGP (หรือ Workflow ERP) คือ ERP ระดับเติบโตสำหรับโรงงานเดียวที่มีพนักงาน 20–200 คน ซื้อแบบโมดูลได้ ติดตั้งภายใน 3–6 เดือน ทั้งคู่ใช้ DNA การผลิตเดียวกันและสเกลได้—ลูกค้าหลายรายเริ่มจาก iGP แล้วอัพเกรดเป็น T100 เมื่อเติบโต</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin ERP ได้รับการรับรองสำหรับภาษีไทยและ BOI compliance หรือไม่?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">ใช่ DigiWin ERP ได้รับการรับรองจากกรมสรรพากรสำหรับ e-Tax filing และมีระบบ WHT (ภาษีหัก ณ ที่จ่าย) VAT และ BOI (คณะกรรมการส่งเสริมการลงทุน) ในตัว ระบบติดตามการใช้วัสดุจริงในระดับใบสั่งผลิต—ไม่ใช่การคำนวณตามทฤษฎี BOM—ดังนั้นรายงาน BOI ของคุณตรงกับสิ่งที่ผู้ตรวจสอบคาดหวัง ลูกค้ารายหนึ่งลดภาษีเพิ่มเติมจากกว่า 10 ล้านบาทต่อปีเหลือศูนย์หลังเปลี่ยนมาใช้ DigiWin</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">การติดตั้ง DigiWin ERP ใช้เวลานานแค่ไหน?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">การติดตั้ง iGP โดยทั่วไปใช้เวลา 3–6 เดือนสำหรับโรงงานเดียว T100 ระดับองค์กรใช้เวลา 6–9 เดือนสำหรับหลายโรงงาน ซึ่งเร็วกว่า ERP ระดับเดียวกันมาก (ปกติ 12–18 เดือน) ความเร็วนี้มาจากเทมเพลตการผลิตสำเร็จรูปที่ผ่านการปรับปรุงจากการติดตั้งกว่า 50,000+ โรงงาน และองค์ความรู้ 44 ปี—คุณไม่ต้องเริ่มจากศูนย์</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin ERP เทียบกับ SAP, Oracle หรือ Infor สำหรับการผลิตเป็นอย่างไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">DigiWin ERP ให้ความสามารถประมาณ 90% ของ ERP ระดับ Tier-1 ในราคาประมาณ 70% ของต้นทุน ติดตั้งเร็วกว่ามาก ต่างจาก ERP แนวราบที่ให้บริการธนาคาร ค้าปลีก และโรงพยาบาล DigiWin สร้างมาเพื่อการผลิตโดยเฉพาะ—พร้อมรองรับ BOM (รายการวัสดุ), จัดตารางสายการผลิต, ควบคุมคุณภาพ, และคิดต้นทุนการผลิตตั้งแต่แรก ซึ่งเป็นสิ่งที่ ERP อื่นต้อง Customize ราคาแพง มักเพิ่มเวลาโปรเจกต์อีกหลายเดือน</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin ERP เชื่อมต่อกับ MES, WMS และ AIoT ได้หรือไม่?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">ได้ ทุกผลิตภัณฑ์ DigiWin—ERP, MES (ระบบปฏิบัติการผลิต), WMS (ระบบจัดการคลังสินค้า) และ AIoT—สร้างบนแพลตฟอร์มเดียวกันด้วยฐานข้อมูลร่วม หมายความว่าไม่ต้องมี Middleware และไม่ต้องกระทบยอดด้วยมือ: ข้อมูลการผลิตไหลจากเครื่องจักรผ่าน MES เข้าบัญชีใน ERP อัตโนมัติ เมื่อเพิ่มโมดูล มันเชื่อมต่อทันทีเพราะใช้แหล่งข้อมูลเดียวกันอยู่แล้ว</p>\n                </div>\n              </details>\n            </div>\n          </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พร้อมเห็นสิ่งที่เป็นไปได้หรือยัง?"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พร้อมเห็นสิ่งที่เป็นไปได้หรือยัง?: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พร้อมเห็นสิ่งที่เป็นไปได้หรือยัง?: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="erp-cta-section">\n    <div class="erp-cta-super-d" aria-hidden="true"></div>\n    <div class="erp-cta-wave-flow" aria-hidden="true"></div>\n    <div class="erp-cta-container">\n      <h2 class="erp-cta-title">พร้อมเห็นสิ่งที่เป็นไปได้หรือยัง?</h2>\n      <p class="erp-cta-subtitle">กรอกแบบฟอร์มแล้วทีมงานจะติดต่อกลับเพื่อพูดคุยเรื่องความท้าทายเฉพาะทางของโรงงานคุณ</p>\n      <div class="erp-cta-btn-row">\n        <a href="/th/demo/" class="erp-cta-btn erp-cta-btn--primary">ติดต่อเรา</a>\n        <a href="/industries.html" class="erp-cta-btn erp-cta-btn--ghost">ดูตามอุตสาหกรรม</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Column"}}},"decoration":{}}} -->\n<!-- wp:html --><style>\n.erp-related-grid{display:grid!important;grid-template-columns:repeat(auto-fit,minmax(280px,1fr))!important;gap:24px!important;max-width:1200px!important;margin:0 auto!important}\n.erp-related-card{display:block!important;padding:24px!important;background:#fff!important;border-radius:12px!important;text-decoration:none!important;border:1px solid #e5e7eb!important;color:#333!important;line-height:1.6!important}\n.erp-related-card-title{font-size:18px!important;font-weight:600!important;color:#000864!important;margin:0 0 8px 0!important}\n.erp-related-card-desc{font-size:14px!important;color:#666!important;margin:0!important}\n</style><div class="erp-related-section">\n    <h2 class="erp-related-heading">สำรวจโซลูชันที่เกี่ยวข้อง</h2>\n    <div class="erp-related-grid">\n      <a href="/products/mes/" class="erp-related-card">\n        <h3 class="erp-related-card-title">MES</h3>\n        <p class="erp-related-card-desc">ระบบปฏิบัติการผลิตแบบ Real-time—ติดตาม OEE, SPC, และใบสั่งผลิตแบบไม่ใช้กระดาษ</p>\n      </a>\n      <a href="/products/wms/" class="erp-related-card">\n        <h3 class="erp-related-card-title">WMS</h3>\n        <p class="erp-related-card-desc">จัดการคลังสินค้าอัจฉริยะด้วยบาร์โค้ด/RFID—ตั้งแต่รับเข้าจนถึงจัดส่ง ตรวจสอบย้อนกลับได้ครบ</p>\n      </a>\n      <a href="/products/aiot/" class="erp-related-card">\n        <h3 class="erp-related-card-title">AIoT</h3>\n        <p class="erp-related-card-desc">เชื่อมต่อเครื่องจักรเข้า ERP โดยตรงด้วยเซ็นเซอร์ IoT, Edge Computing และ AI Analytics</p>\n      </a>\n      <a href="/industries/automotive/" class="erp-related-card">\n        <h3 class="erp-related-card-title">ยานยนต์</h3>\n        <p class="erp-related-card-desc">ERP และ MES ที่สร้างมาเฉพาะสำหรับผู้ผลิตชิ้นส่วนยานยนต์และ OEM suppliers</p>\n      </a>\n      <a href="/industries/electronics/" class="erp-related-card">\n        <h3 class="erp-related-card-title">อิเล็กทรอนิกส์</h3>\n        <p class="erp-related-card-desc">ซอฟต์แวร์การผลิตสำหรับประกอบอิเล็กทรอนิกส์, สาย SMT และตรวจสอบย้อนกลับชิ้นส่วน</p>\n      </a>\n      <a href="/industries/metal-plastics/" class="erp-related-card">\n        <h3 class="erp-related-card-title">โลหะ &amp; พลาสติก</h3>\n        <p class="erp-related-card-desc">โซลูชันบูรณาการสำหรับหล่อ ฉีดพลาสติก และโรงงานขึ้นรูปโลหะ</p>\n      </a>\n    </div>\n  </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100777;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100777 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100777, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HERO (S1) === */\n.erp-super-d{position:absolute;top:50%;right:auto;left:50%;width:80%;min-height:80vh;background:url("data:image/svg+xml;base64,") no-repeat center center;background-size:contain;transform:translate(-50%, -50%);opacity:0.1;pointer-events:none;z-index:0}\n.erp-hero {\n            background: linear-gradient(165deg, #0f1419 0%, #1a2632 40%, #000864 100%) !important;\n            padding: 160px 0 100px;\n            position: relative;\n            overflow: hidden;\n        }\n.erp-hero::before {\n            content: \'\';\n            position: absolute;\n            inset: 0;\n            background-image: url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noiseFilter\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noiseFilter)\'/%3E%3C/svg%3E");\n            opacity: 0.03;\n            pointer-events: none;\n        }\n.erp-hero-bg {\n            position: absolute;\n            inset: 0;\n            pointer-events: none;\n            overflow: hidden;\n        }\n.erp-hero-bg svg {\n            position: absolute;\n            right: 0;\n            top: 50%;\n            transform: translateY(-50%);\n            width: 55%;\n            height: auto;\n            opacity: 0.12;\n        }\n.erp-hero-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 60px;\n            align-items: center;\n            position: relative;\n            z-index: 1;\n        }\n.erp-hero-content {\n            max-width: 600px;\n        }\n.erp-hero-badge {\n            display: inline-flex;\n            align-items: center;\n            gap: 10px;\n            background: rgba(0, 175, 240, 0.1);\n            border: 1px solid rgba(0, 175, 240, 0.3);\n            padding: 10px 20px;\n            border-radius: 50px;\n            color: #0369a1;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            margin-bottom: 24px;\n        \n            line-height: 17.6px;\n\n            -webkit-font-smoothing: auto;\n}\n.erp-hero-badge::before {\n            content: \'\';\n            width: 8px;\n            height: 8px;\n            background: #0369a1;\n            border-radius: 50%;\n        }\n.erp-hero h1 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(36px, 4.5vw, 52px);\n            font-weight: 700;\n            color: #ffffff;\n            margin: 0 0 24px 0;\n            line-height: 1.15;\n            letter-spacing: -0.02em;\n        }\n.erp-hero h1 .highlight {\n            color: #0369a1;\n        \n            -webkit-font-smoothing: auto;\n}\n.erp-hero-subtitle {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 19px;\n            color: rgba(255, 255, 255, 0.8);\n            line-height: 1.7;\n            margin-bottom: 36px;\n        \n            -webkit-font-smoothing: auto;\n}\n.erp-hero-ctas {\n            display: flex;\n            gap: 16px;\n            flex-wrap: wrap;\n            margin-bottom: 48px;\n        }\n.erp-hero-stats {\n            display: flex;\n            gap: 40px;\n            padding-top: 32px;\n            border-top: 1px solid rgba(255, 255, 255, 0.1);\n        }\n.erp-hero-stat {\n            text-align: left;\n        }\n.erp-hero-stat-number {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 32px;\n            font-weight: 800;\n            color: #0369a1;\n            letter-spacing: -0.02em;\n        \n            line-height: 51.2px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.erp-hero-stat-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            color: rgba(255, 255, 255, 0.75);\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            margin-top: 4px;\n        \n            line-height: 16px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.erp-hero-visual {\n            position: relative;\n        }\n.erp-dashboard-mockup {\n            background: #000864;\n            border-radius: 16px;\n            border: 1px solid rgba(255, 255, 255, 0.1);\n            padding: 20px;\n            box-shadow: 0 40px 80px rgba(0, 0, 0, 0.4);\n        }\n.mockup-content {\n            background: rgba(255, 255, 255, 0.03);\n            border-radius: 8px;\n            padding: 20px;\n            min-height: 280px;\n        }\n.mockup-grid {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 12px;\n            margin-bottom: 16px;\n        }\n.mockup-card {\n            background: rgba(255, 255, 255, 0.05);\n            border-radius: 8px;\n            padding: 16px;\n        }\n.mockup-card-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 20px;\n            font-weight: 700;\n            color: #ffffff;\n        \n            line-height: 32px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.mockup-card-value.green { color: rgb(4, 120, 87); }\n.mockup-card-value.blue { color: #0369a1; }\n.mockup-chart {\n            background: rgba(255, 255, 255, 0.03);\n            border-radius: 8px;\n            padding: 16px;\n            height: 100px;\n            display: flex;\n            align-items: flex-end;\n            gap: 8px;\n        }\n.integration-node.active {\n            border-color: #0369a1;\n            background: linear-gradient(135deg, rgba(3, 105, 161, 0.05), #ffffff);\n            box-shadow: 0 8px 32px rgba(3, 105, 161, 0.15);\n        }\n@media (max-width: 1024px) {\n            .erp-hero-inner {\n                grid-template-columns: 1fr;\n                text-align: center;\n            }\n\n            .erp-hero-content {\n                max-width: 100%;\n            }\n\n            .erp-hero-stats {\n                justify-content: center;\n            }\n\n            .erp-hero-visual {\n                display: none;\n            }\n\n            .erp-hero-bg svg {\n                opacity: 0.06;\n                width: 80%;\n                right: -20%;\n            }\n\n            .pain-grid, .products-comparison {\n                grid-template-columns: 1fr;\n                max-width: 600px;\n                margin-left: auto;\n                margin-right: auto;\n            }\n\n            .integration-visual {\n                flex-direction: column;\n            }\n\n            .integration-node {\n                width: auto;\n                height: auto;\n            }\n\n            .integration-arrow {\n                transform: rotate(90deg);\n            }\n\n            .boi-callout-grid {\n                grid-template-columns: 1fr !important;\n                text-align: center;\n            }\n\n            .boi-callout-grid > div:first-child {\n                text-align: center;\n            }\n\n            .erpii-modules-grid {\n                grid-template-columns: repeat(2, 1fr);\n            }\n\n            .erp-trust-callout {\n                flex-direction: column;\n            }\n        }\n@media (prefers-reduced-motion: reduce) {\n            .erp-hero-content,\n            .erp-hero::before,\n            .erp-hero-badge::before,\n            .erp-dashboard-mockup,\n            .pain-card,\n            .pain-card-icon,\n            .product-card,\n            .weapon-card,\n            .challenge-icon,\n            .integration-link,\n            .erp-use-case-pill,\n            .erp-erpii-accordion summary,\n            .boi-enforcement-cta,\n            .dw-d-parallax,\n            .dw-wave-flow,\n            .dw-wave-fade,\n            .dw-d-bg {\n                animation: none !important;\n                transition: none !important;\n            }\n        }\n@media (max-width: 640px) {\n            .erp-hero {\n                padding: 120px 0 80px;\n            }\n\n            .erp-hero-stats {\n                flex-direction: column;\n                gap: 24px;\n                align-items: center;\n            }\n\n            .erp-hero-stat {\n                text-align: center;\n            }\n\n            .erp-cta-buttons {\n                flex-direction: column;\n            }\n        }\n\n/* Buttons */\n.btn-white{background:#ffffff;color:#003CC8;padding:20px 40px;border-radius:14px;font-family:\'Noto Sans\', sans-serif;font-size:16px;font-weight:600;text-decoration:none;transition:all 0.4s cubic-bezier(0.4, 0, 0.2, 1);box-shadow:0 4px 20px rgba(0, 0, 0, 0.15);display:inline-flex;align-items:center;gap:10px;line-height:25.6px !important;-webkit-font-smoothing:auto}\n.btn-white:hover{transform:translateY(-4px);box-shadow:0 16px 48px rgba(0, 0, 0, 0.2)}\n.btn-outline-white{background:transparent;color:#ffffff;padding:20px 40px;border-radius:14px;border:2px solid rgba(255, 255, 255, 0.5);font-family:\'Noto Sans\', sans-serif;font-size:16px;font-weight:600;text-decoration:none;transition:all 0.3s ease;line-height:25.6px !important;-webkit-font-smoothing:auto}\n.btn-outline-white:hover{background:rgba(255, 255, 255, 0.15);border-color:#ffffff}\n/* Dashboard mockup */\n.mockup-header{display:flex;gap:8px;margin-bottom:16px}\n.mockup-dot{width:12px;height:12px;border-radius:50%;background:rgba(255, 255, 255, 0.15)}\n.mockup-dot:nth-child(1){background:#ff5f57}\n.mockup-dot:nth-child(2){background:#ffbd2e}\n.mockup-dot:nth-child(3){background:#28ca42}\n.mockup-nav{display:flex;gap:16px;margin-bottom:20px;padding-bottom:12px;border-bottom:1px solid rgba(255, 255, 255, 0.1)}\n.mockup-nav-item{font-family:\'JetBrains Mono\', monospace;font-size:10px;color:rgba(255, 255, 255, 0.85) !important;text-transform:uppercase;letter-spacing:0.05em\n            line-height: 16px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.mockup-nav-item.active{color:#0369a1}\n.mockup-card-label{font-family:\'JetBrains Mono\', monospace;font-size:9px;color:rgba(255, 255, 255, 0.85);text-transform:uppercase;margin-bottom:8px\n            line-height: 14.4px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.mockup-bar{flex:1;background:rgb(0, 175, 240) !important;border-radius:4px 4px 0 0;opacity:0.6}\n.mockup-bar.active{opacity:1;background:#10b981}\n\n@media(prefers-reduced-motion:reduce){}\n\n.mockup-nav-item {\n            line-height: 16px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.erp-hero-stat-label {\n            line-height: 16px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.erp-hero-stat-number {\n            line-height: 51.2px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n\n.erp-hero-stat-label {\n            line-height: 16p