ease;\n        }\n.boi-enforcement-cta:hover {\n            color: #92400e;\n        }\n.boi-enforcement-cta svg {\n            width: 16px;\n            height: 16px;\n            stroke: currentColor;\n            stroke-width: 2;\n            fill: none;\n        }\n.boi-enforcement-source {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 12px;\n            color: #a16207;\n            margin-top: 16px;\n            font-style: italic;\n        }\n@media (max-width: 1024px) {\n            .erp-hero-inner {\n                grid-template-columns: 1fr;\n                text-align: center;\n            }\n\n            .erp-hero-content {\n                max-width: 100%;\n            }\n\n            .erp-hero-stats {\n                justify-content: center;\n            }\n\n            .erp-hero-visual {\n                display: none;\n            }\n\n            .erp-hero-bg svg {\n                opacity: 0.06;\n                width: 80%;\n                right: -20%;\n            }\n\n            .pain-grid, .products-comparison {\n                grid-template-columns: 1fr;\n                max-width: 600px;\n                margin-left: auto;\n                margin-right: auto;\n            }\n\n            .integration-visual {\n                flex-direction: column;\n            }\n\n            .integration-node {\n                width: auto;\n                height: auto;\n            }\n\n            .integration-arrow {\n                transform: rotate(90deg);\n            }\n\n            .boi-callout-grid {\n                grid-template-columns: 1fr !important;\n                text-align: center;\n            }\n\n            .boi-callout-grid > div:first-child {\n                text-align: center;\n            }\n\n            .erpii-modules-grid {\n                grid-template-columns: repeat(2, 1fr);\n            }\n\n            .erp-trust-callout {\n                flex-direction: column;\n            }\